mapper.select:
SELECT DISTINCT u.user_id AS userId, u.name AS name, u.user_name AS userName, u.avatar_url AS avatarUrl FROM ( SELECT user_id FROM pr WHERE repo_id = #{repoId}
UNION
SELECT pr.user_id FROM commit JOIN pr ON commit.pr_id = pr.pr_id AND commit.repo_id = pr.repo_id WHERE commit.repo_id = #{repoId}
UNION
SELECT user_id FROM comment WHERE repo_id = #{repoId} AND user_id IS NOT NULL
UNION
SELECT user_id FROM reply WHERE repo_id = #{repoId} AND user_id IS NOT NULL ) AS participants JOIN users u ON participants.user_id = u.user_id;

SELECT COUNT(pr.pr_id) AS totalMergeRequest
FROM pr
WHERE pr.repo_id = #{repoId}

SELECT
    COUNT(pr.pr_id) AS prCount
FROM pr
WHERE pr.repo_id = #{repoId}
    AND pr.user_id = #{userId}
    AND pr.create_at >= DATE_FORMAT(NOW() - INTERVAL 6 WEEK, '%Y-%m-%dT%H:%i:%s.%f+09:00');

SELECT
    COUNT(commit.commit_id) AS commitCount
FROM commit
JOIN pr ON commit.pr_id = pr.pr_id AND commit.repo_id = pr.repo_id
WHERE commit.repo_id = #{repoId}
    AND pr.user_id = #{userId}
    AND commit.commited_at >= DATE_FORMAT(NOW() - INTERVAL 6 WEEK, '%Y-%m-%dT%H:%i:%s.%f+09:00');

SELECT
    COUNT(DISTINCT c.comment_id) + COUNT(DISTINCT r.re_comment_id) AS commentCount
FROM comment c
LEFT JOIN reply r ON c.comment_id = r.comment_id AND c.pr_id = r.pr_id AND c.repo_id = r.repo_id
WHERE c.repo_id = #{repoId}
    AND c.user_id = #{userId}
    AND c.create_at >= DATE_FORMAT(NOW() - INTERVAL 6 WEEK, '%Y-%m-%dT%H:%i:%s.%f+09:00');
